async (params, browser) => {
  // Open Telegram Web
  await browser.open('https://web.telegram.org/k/')

  // Wait for Telegram to load
  await browser.waitForSelector('.input-search input, .chatlist-chat, .chat-list', 15000)

  // Let app fully initialize
  await browser.wait(2000)

  // Open sidebar menu
  const open_menu = await browser.evaluate(`const hamburgerBtn = document.querySelector('.btn-menu-toggle, .sidebar-header .btn-icon, .menu-hamburger'); if (hamburgerBtn) { hamburgerBtn.click(); } return { opened_menu: true }`)

  await browser.wait(1000)

  // Click Contacts menu item
  const click_contacts = await browser.evaluate(`const menuItems = document.querySelectorAll('.btn-menu-item, .menu-item, [class*="MenuItem"]'); let clicked = false; for (const item of menuItems) { const text = item.textContent.trim().toLowerCase(); if (text.includes('contact') || text.includes('people')) { item.click(); clicked = true; break; } } return { clicked_contacts: clicked }`)

  // Wait for contacts to load
  await browser.wait(2500)

  // Extract contacts list
  const contacts_list = await browser.evaluate(`const contacts = []; const contactEls = document.querySelectorAll('.contacts-container .row, .chatlist-chat, .search-group .chatlist-chat, .sidebar-slider .chatlist-chat'); for (let i = 0; i < Math.min(contactEls.length, 50); i++) { const el = contactEls[i]; const nameEl = el.querySelector('.peer-title, .user-title, .dialog-title'); const statusEl = el.querySelector('.user-last-message, .dialog-subtitle, .status, .last-seen'); contacts.push({ name: nameEl ? nameEl.textContent.trim() : '', last_seen: statusEl ? statusEl.textContent.trim() : '' }); } return { contact_count: contacts.length, contacts: contacts }`)

  return contacts_list
}
